terms2 = [
    {"tr": "Bono", "en": "Promissory Note", "slug": "promissory-note", "tag": "commercial-law", "def": "A promissory note (Bono) is a written promise by one party (the maker) to pay a specific sum of money to another (the payee) at a determined future date.", "faq_q": "Are promissory notes widely used in Turkey?", "faq_a": "Yes, promissory notes are heavily used in Turkish B2B and B2C transactions as they provide a direct, fast track for debt execution."},
    {"tr": "Kambiyo Senedi", "en": "Negotiable Instruments", "slug": "negotiable-instruments", "tag": "commercial-law", "def": "Negotiable instruments are specialized documents guaranteeing the payment of a specific amount of money, primarily encompassing cheques, bills of exchange, and promissory notes under Turkish law.", "faq_q": "What is the advantage of a negotiable instrument?", "faq_a": "They benefit from highly expedited and strict execution procedures (Kambiyo Takipleri) in debt collection."},
    {"tr": "İbraz", "en": "Presentation", "slug": "presentation", "tag": "commercial-law", "def": "Presentation is the formal act of physically or electronically presenting a negotiable instrument (like a cheque) to the bank or drawee for payment within legally mandated timeframes.", "faq_q": "What is the presentation period for cheques in Turkey?", "faq_a": "Cheques drawn and payable in Turkey must be presented to the bank within 10 days of the issuance date written on the cheque."},
    {"tr": "Protesto", "en": "Protest", "slug": "protest", "tag": "commercial-law", "def": "A formal, notarized declaration attesting that a negotiable instrument was presented for payment or acceptance and was dishonored.", "faq_q": "Is a protest always required?", "faq_a": "For bills of exchange and promissory notes, drawing a protest is usually required to protect recourse rights against endorsers, unless a 'without protest' clause is added."},
    {"tr": "Ayni Sermaye", "en": "In-Kind Capital", "slug": "in-kind-capital", "tag": "company-law", "def": "Capital contributed to a company in forms other than cash, such as real estate, machinery, intellectual property, or existing businesses, subject to court-appointed valuation.", "faq_q": "Can any asset be contributed as in-kind capital?", "faq_a": "No, the asset must have an assignable economic value. Services, personal labor, and overdue receivables cannot be contributed as capital in joint-stock companies."},
    {"tr": "İpotek", "en": "Mortgage", "slug": "mortgage", "tag": "real-estate", "def": "A mortgage (İpotek) is a real right established on immovable property (real estate) to secure the payment of a debt, requiring official registration at the Land Registry.", "faq_q": "How is a mortgage enforced?", "faq_a": "If the debt is not paid, the creditor can initiate execution proceedings to sell the mortgaged property via public auction to satisfy the debt."},
    {"tr": "Rehin", "en": "Pledge", "slug": "pledge", "tag": "contract-law", "def": "A pledge is a security interest created over movable property or rights to secure a debt. Traditionally, the pledged asset must be physically delivered to the creditor.", "faq_q": "Can a pledge be established without physical delivery?", "faq_a": "Yes, specific laws like the Commercial Enterprise Pledge Law allow pledges on movable business assets without transferring possession."},
    {"tr": "Ticari İşletme Rehni", "en": "Commercial Enterprise Pledge", "slug": "commercial-enterprise-pledge", "tag": "commercial-law", "def": "A specialized pledge allowing a merchant to use their entire commercial enterprise (including machinery, inventory, and trade name) as collateral without handing over physical possession.", "faq_q": "Where is a commercial enterprise pledge registered?", "faq_a": "It is registered in the Movable Pledge Registry (TAKSBİS), providing transparency to third parties and lenders."},
    {"tr": "İhtarname", "en": "Notice / Warning", "slug": "notice-warning", "tag": "contract-law", "def": "A formal legal notice, typically sent via a Notary Public, to formally demand the performance of an obligation, declare default, or terminate a contract.", "faq_q": "Why use a Notary for an Ihtarname?", "faq_a": "While not always legally mandatory, notarized notices provide indisputable proof of the content sent and the exact date of receipt by the other party."},
    {"tr": "Menfi Tespit", "en": "Negative Declaratory Action", "slug": "negative-declaratory-action", "tag": "dispute-resolution", "def": "A lawsuit filed by a debtor seeking a binding court declaration that they do not actually owe a specific debt claimed by the creditor.", "faq_q": "Does a negative declaratory action stop debt execution?", "faq_a": "It does not automatically stop execution proceedings. The debtor must usually deposit 115% of the debt as collateral to obtain an injunction halting the execution."},
    {"tr": "İstirdat", "en": "Action for Restitution", "slug": "action-for-restitution", "tag": "dispute-resolution", "def": "A lawsuit to recover money that a debtor was forced to pay during execution proceedings for a debt that they legally did not owe.", "faq_q": "When must an action for restitution be filed?", "faq_a": "It must be filed within one year from the date the unjust payment was made to the execution office."},
    {"tr": "İtirazın İptali", "en": "Annulment of Objection", "slug": "annulment-of-objection", "tag": "dispute-resolution", "def": "A lawsuit filed by a creditor after a debtor formally objects to and halts an execution proceeding without judgment, seeking to annul the objection and resume execution.", "faq_q": "Is there a penalty for unjust objections?", "faq_a": "Yes, if the creditor proves the debt, the court may order the debtor to pay an execution denial compensation of at least 20% of the debt."},
    {"tr": "İtirazın Kaldırılması", "en": "Lifting of Objection", "slug": "lifting-of-objection", "tag": "dispute-resolution", "def": "A faster, narrower alternative to Annulment of Objection, applied directly to the Execution Court, but only permissible if the creditor possesses strict statutory proof of the debt (like a notarized document).", "faq_q": "Can any debt be proven in this procedure?", "faq_a": "No, it strictly requires specific documentary evidence defined in Article 68 of the Execution and Bankruptcy Law."},
    {"tr": "Sıra Cetveli", "en": "Table of Ranks", "slug": "table-of-ranks", "tag": "commercial-law", "def": "A ranked list prepared by the execution or bankruptcy office determining the priority order in which competing creditors will be paid from the liquidation of a debtor's assets.", "faq_q": "Who gets paid first in the Table of Ranks?", "faq_a": "State taxes, employee wages, and secured creditors (like mortgage holders) generally have statutory priority over ordinary unsecured creditors."},
    {"tr": "Tasarrufun İptali", "en": "Actio Pauliana / Cancellation of Disposition", "slug": "actio-pauliana", "tag": "commercial-law", "def": "A lawsuit allowing creditors to annul fraudulent asset transfers made by a debtor aiming to hide assets and evade debt collection.", "faq_q": "What transfers can be canceled?", "faq_a": "Donations, transactions at severe undervaluations, and asset transfers made to relatives or close associates right before bankruptcy or execution can be canceled."},
    {"tr": "Kayyım", "en": "Trustee / Receiver", "slug": "trustee-receiver", "tag": "company-law", "def": "A court-appointed official tasked with temporarily managing a company, an estate, or property when the regular management is incapacitated, deadlocked, or legally suspended.", "faq_q": "When is a trustee appointed to a company?", "faq_a": "A trustee is often appointed during severe shareholder deadlocks, criminal investigations regarding corporate management, or pending the resolution of an dissolution lawsuit."},
    {"tr": "Konkordato Komiseri", "en": "Concordat Commissioner", "slug": "concordat-commissioner", "tag": "company-law", "def": "An independent expert appointed by the commercial court to supervise a debtor's business operations and protect creditors' interests during the concordat restructuring period.", "faq_q": "Does the Commissioner run the company?", "faq_a": "Not necessarily. Typically, management remains with the debtor, but major transactions require the Commissioner's prior approval."},
    {"tr": "İflas İdaresi", "en": "Bankruptcy Administration", "slug": "bankruptcy-administration", "tag": "company-law", "def": "The official body formed after a bankruptcy declaration, responsible for representing the bankrupt estate, collecting assets, assessing claims, and distributing proceeds to creditors.", "faq_q": "Who elects the Bankruptcy Administration?", "faq_a": "It is typically elected by the assembly of creditors and appointed by the execution court."},
    {"tr": "Masaya Kayıt", "en": "Registration to the Bankruptcy Estate", "slug": "registration-to-the-bankruptcy-estate", "tag": "commercial-law", "def": "The formal process where creditors submit their claims and supporting evidence to the bankruptcy administration to be included in the liquidation distributions.", "faq_q": "Is there a deadline for registering claims?", "faq_a": "Yes, creditors must usually register their claims within one month following the official announcement of the bankruptcy."},
    {"tr": "Şüpheli Alacak", "en": "Doubtful Receivable", "slug": "doubtful-receivable", "tag": "tax-law", "def": "A commercial receivable that is in the litigation or execution phase and whose collection has become uncertain, allowing businesses to set aside a tax-deductible provision.", "faq_q": "Can any unpaid invoice be deemed a doubtful receivable?", "faq_a": "No, to be tax-deductible, formal legal action (lawsuit or execution proceeding) must have actively commenced against the debtor."},
    {"tr": "Mahsuplaşma", "en": "Netting", "slug": "netting", "tag": "commercial-law", "def": "The accounting and legal process of consolidating multiple mutual obligations or financial positions between two parties to arrive at a single net payable amount.", "faq_q": "How does netting differ from set-off?", "faq_a": "Netting often refers to broader, systemic consolidation of multiple transactions (common in banking), while set-off is the legal extinguishing of two specific mutual debts."},
    {"tr": "Takas", "en": "Set-Off", "slug": "set-off", "tag": "contract-law", "def": "The legal right to extinguish mutual, due, and homogenous debts between two parties up to the amount of the smaller debt, simply by unilateral declaration.", "faq_q": "Can set-off be executed automatically?", "faq_a": "No, set-off does not happen automatically under Turkish law; one party must explicitly declare their intent to set-off to the other party."},
    {"tr": "Mutabakat", "en": "Reconciliation", "slug": "reconciliation", "tag": "commercial-law", "def": "The process where two commercial parties review and formally agree upon their mutual account balances, preventing future disputes over amounts owed.", "faq_q": "What happens if a reconciliation statement is ignored?", "faq_a": "In commercial practice, if a party does not object to a formal account statement or invoice within 8 days, they are generally deemed to have accepted its contents."},
    {"tr": "Fatura", "en": "Invoice", "slug": "invoice", "tag": "commercial-law", "def": "A commercial document issued by a seller to a buyer detailing the goods or services provided, prices, and taxes, serving as primary evidence of a commercial transaction.", "faq_q": "What is the legal deadline to object to an invoice?", "faq_a": "Under the Turkish Commercial Code, a party has 8 days to object to the contents of an invoice received; otherwise, it is legally presumed accepted."},
    {"tr": "İrsaliye", "en": "Waybill", "slug": "waybill", "tag": "commercial-law", "def": "A dispatch note or delivery document that strictly tracks the physical movement and delivery of goods from a supplier to a buyer, separate from the financial invoice.", "faq_q": "Is an e-Waybill mandatory in Turkey?", "faq_a": "Yes, for many medium-to-large taxpayers and specific sectors, issuing electronic waybills (e-İrsaliye) is a strict legal and tax requirement."},
    {"tr": "Cari Hesap", "en": "Current Account", "slug": "current-account", "tag": "commercial-law", "def": "A commercial arrangement where two parties agree that their mutual receivables arising from continuous transactions will not be claimed individually but netted out periodically.", "faq_q": "How often is a current account settled?", "faq_a": "By law, unless agreed otherwise, current accounts are balanced and settled at the end of each calendar year."},
    {"tr": "Avans", "en": "Advance Payment", "slug": "advance-payment", "tag": "contract-law", "def": "A partial payment made by a buyer to a seller before the goods are delivered or services are fully rendered, acting as financing or security for the contract.", "faq_q": "Must an advance payment be returned if the contract fails?", "faq_a": "Yes, if the contract is canceled or unfulfilled without fault, the advance payment must generally be returned under unjust enrichment rules."},
    {"tr": "Peşinat", "en": "Down Payment", "slug": "down-payment", "tag": "contract-law", "def": "An initial, upfront payment made at the time of finalizing a contract, establishing commitment. In Turkish law, it is often treated as earnest money or a penalty depending on drafting.", "faq_q": "Is a down payment refundable?", "faq_a": "It depends. If classified as 'earnest money' (Pey Akçesi), it is usually deducted from the total. If classified as 'forfeit money' (Cayma Akçesi), the defaulting party loses it."},
    {"tr": "Hakediş", "en": "Progress Payment", "slug": "progress-payment", "tag": "contract-law", "def": "Periodic payments made to contractors in construction or long-term service agreements based on the certified completion of specific milestones or work percentages.", "faq_q": "Who approves a progress payment?", "faq_a": "Typically, the employer's architect, engineer, or project manager must review and certify the hakediş report before payment is due."},
    {"tr": "Külli Halefiyet", "en": "Universal Succession", "slug": "universal-succession", "tag": "company-law", "def": "A legal principle where an entity (or heir) inherits the entirety of another's rights, assets, and liabilities automatically and completely, without needing individual transfers.", "faq_q": "When does universal succession occur in corporate law?", "faq_a": "It occurs during company mergers. The absorbing company automatically assumes all contracts, debts, and assets of the merged company in one stroke."},
    {"tr": "Karz", "en": "Loan of Consumption", "slug": "loan-of-consumption", "tag": "contract-law", "def": "A specific type of loan agreement where the lender transfers ownership of money or fungible goods to the borrower, who is obligated to return the same quantity and quality.", "faq_q": "Is interest mandatory in a Karz agreement?", "faq_a": "In civil (non-commercial) loans, interest is only payable if explicitly agreed. In commercial loans, interest is implied and payable even if not written."},
    {"tr": "Kaynak Kod", "en": "Source Code", "slug": "source-code", "tag": "intellectual-property", "def": "The human-readable version of computer software. Under Turkish copyright law, source code is strictly protected as a literary work.", "faq_q": "Who owns the source code created by an employee?", "faq_a": "Under Turkish Copyright Law, unless agreed otherwise, the financial rights to software and source code developed by an employee during their duties belong automatically to the employer."},
    {"tr": "Hizmet Seviyesi Sözleşmesi", "en": "Service Level Agreement (SLA)", "slug": "service-level-agreement", "tag": "contract-law", "def": "A contract specifying the exact standards of performance, uptime, and quality metrics a service provider must deliver, commonly used in IT and outsourcing.", "faq_q": "What happens if SLA metrics are not met?", "faq_a": "SLAs usually contain specific penalty clauses or service credits that the provider must pay or apply to future invoices for failing to meet the metrics."},
    {"tr": "Dış Kaynak", "en": "Outsourcing", "slug": "outsourcing", "tag": "commercial-law", "def": "The business practice of contracting external specialized providers to handle specific business functions (like IT, payroll, or customer service) previously done in-house.", "faq_q": "Does outsourcing trigger employee transfer rules?", "faq_a": "Yes, if outsourcing constitutes a 'transfer of workplace' under Turkish Labor Law, existing employees and their accumulated rights may automatically transfer to the outsourcing provider."},
    {"tr": "Beyanname", "en": "Declaration", "slug": "declaration", "tag": "tax-law", "def": "A formal, legally binding statement or document submitted to governmental authorities, most commonly referring to tax or customs declarations.", "faq_q": "What are the common corporate tax declarations?", "faq_a": "Companies must submit monthly VAT declarations, quarterly advance corporate tax declarations, and an annual corporate tax declaration."},
    {"tr": "Tahakkuk", "en": "Accrual", "slug": "accrual", "tag": "tax-law", "def": "The formal assessment and establishment of a tax liability by the tax authority, making the calculated tax officially due and payable.", "faq_q": "What is an accrual slip (Tahakkuk Fişi)?", "faq_a": "It is an official receipt issued by the tax office after a tax declaration is submitted, showing the exact amount of tax owed and the payment deadline."},
    {"tr": "Vergi Ziyaı", "en": "Tax Loss", "slug": "tax-loss", "tag": "tax-law", "def": "A tax penalty mechanism triggered when a taxpayer's failure to comply with obligations causes the State to lose tax revenue or receive it late.", "faq_q": "What is the penalty for tax loss?", "faq_a": "The standard penalty is one time the amount of the evaded tax. However, if evasion involves forgery or fraud, the penalty can be tripled and lead to criminal charges."},
    {"tr": "Özel Usulsüzlük", "en": "Special Irregularity", "slug": "special-irregularity", "tag": "tax-law", "def": "Administrative tax penalties levied for violating strict procedural and documentation rules, such as failing to issue an invoice, regardless of whether tax revenue was lost.", "faq_q": "Is special irregularity separate from tax loss?", "faq_a": "Yes, a company can be fined for special irregularity (e.g., missing invoices) even if they perfectly paid all their taxes on time."},
    {"tr": "Bağımsız Denetim", "en": "Independent Audit", "slug": "independent-audit", "tag": "company-law", "def": "An objective examination of a company's financial statements by licensed external auditors to ensure compliance with Turkish Financial Reporting Standards (TFRS).", "faq_q": "Are all Turkish companies subject to independent audit?", "faq_a": "No, only companies meeting specific criteria set by the President (usually based on assets, revenue, and employee thresholds) are subject to mandatory independent audits."},
    {"tr": "Hakim Şirket", "en": "Parent Company", "slug": "parent-company", "tag": "company-law", "def": "A company that exerts direct or indirect control over another entity (the subsidiary), usually by holding the majority of voting rights or the right to appoint the board.", "faq_q": "Can a parent company be held liable for a subsidiary's debts?", "faq_a": "Generally no, due to the principle of separate legal personality. However, under group company rules, a parent abusing its control to the detriment of the subsidiary can be held liable."},
    {"tr": "Pay Defteri", "en": "Share Ledger", "slug": "share-ledger", "tag": "company-law", "def": "The official statutory book maintained by a company recording the names, addresses, and shareholdings of its registered shareholders.", "faq_q": "Is registration in the share ledger mandatory?", "faq_a": "Yes, for registered shares, a person is only legally recognized as a shareholder by the company if they are properly recorded in the share ledger."},
    {"tr": "Yönetim Kurulu Karar Defteri", "en": "Board of Directors Resolution Book", "slug": "board-of-directors-resolution-book", "tag": "company-law", "def": "A mandatory, notarized corporate book where all official decisions and resolutions taken by the company's Board of Directors are recorded and signed.", "faq_q": "Must every decision be recorded here?", "faq_a": "Yes, all formal board resolutions must be inscribed in this book, signed by the attending members, and presented during audits or legal disputes."},
    {"tr": "Envanter", "en": "Inventory", "slug": "inventory", "tag": "commercial-law", "def": "A detailed, itemized record of a company's commercial assets, liabilities, goods, and raw materials, required to be prepared at the establishment and end of each fiscal year.", "faq_q": "Is the inventory legally binding?", "faq_a": "Yes, the inventory book is a mandatory commercial book under the Turkish Commercial Code and forms the foundation for the balance sheet."},
    {"tr": "Bilanço", "en": "Balance Sheet", "slug": "balance-sheet", "tag": "commercial-law", "def": "A core financial statement summarizing a company's assets, liabilities, and shareholders' equity at a specific point in time, reflecting its financial health.", "faq_q": "Who approves the balance sheet?", "faq_a": "The balance sheet is prepared by management and must be formally approved by the General Assembly during the annual ordinary meeting."},
    {"tr": "Konsorsiyum", "en": "Consortium", "slug": "consortium", "tag": "company-law", "def": "A collaborative association of two or more entities pooling their resources to execute a specific, large-scale project while remaining independent and separately liable for their distinct portions of work.", "faq_q": "How does a consortium differ from a joint venture?", "faq_a": "In a joint venture, partners are jointly liable for the entire project. In a consortium, each partner is technically only liable for their specific, predefined portion of the work."},
    {"tr": "Adi Ortaklık", "en": "Ordinary Partnership", "slug": "ordinary-partnership", "tag": "company-law", "def": "The simplest form of business partnership under the Turkish Code of Obligations, lacking a separate legal personality, where partners are jointly and unlimitedly liable for partnership debts.", "faq_q": "Does an ordinary partnership have a trade name?", "faq_a": "Because it lacks legal personality, it cannot register its own trade name or own property in its own name; assets are owned jointly by the partners."},
    {"tr": "Faktoring", "en": "Factoring", "slug": "factoring", "tag": "commercial-law", "def": "A financial transaction where a business sells its accounts receivable (invoices) to a third-party financial institution (factor) at a discount to secure immediate cash flow.", "faq_q": "Is factoring highly regulated in Turkey?", "faq_a": "Yes, factoring companies must be licensed by the Banking Regulation and Supervision Agency (BRSA) and follow strict financial regulations."},
    {"tr": "Cüzi Halefiyet", "en": "Singular Succession", "slug": "singular-succession", "tag": "contract-law", "def": "A legal transfer mechanism where only a specific, individual asset, right, or debt is transferred from one party to another, as opposed to an entire estate.", "faq_q": "What is an example of singular succession?", "faq_a": "The sale of a company car or the assignment of a specific invoice receivable are examples of singular succession."},
    {"tr": "Niyet Mektubu", "en": "Letter of Intent (LOI)", "slug": "letter-of-intent", "tag": "contract-law", "def": "A preliminary document outlining the basic terms and understandings of an anticipated contract or M&A transaction before a binding final agreement is drafted.", "faq_q": "Is an LOI legally binding in Turkey?", "faq_a": "Generally no, regarding the main transaction. However, specific clauses like confidentiality, exclusivity, and governing law within the LOI are usually drafted to be legally binding."},
    {"tr": "Mutlak Butlan", "en": "Absolute Nullity", "slug": "absolute-nullity", "tag": "contract-law", "def": "The severe legal status of a contract that is entirely void from its inception because it violates mandatory laws, public morality, or lacks essential form requirements.", "faq_q": "Can a contract with absolute nullity be fixed later?", "faq_a": "No, a contract subject to absolute nullity cannot be validated by the passage of time or subsequent agreement; a judge must recognize the nullity ex officio."}
]
